var fd = tree.root.get_node("/root/Main/FormationsDialog")
var q = [fd]
while not q.is_empty():
	var nd = q.pop_back()
	if nd is OptionButton and nd.item_count > 0 and nd.get_item_text(0) == "(Unattached)":
		nd.select(1)
		nd.item_selected.emit(1)
		return true
	for c in nd.get_children():
		q.append(c)
return false

var fd = tree.root.get_node("/root/Main/FormationsDialog")
var q = [fd]
while not q.is_empty():
	var nd = q.pop_back()
	if nd is CheckBox and str(nd.text).begins_with("Boyz") and not ("Reserves" in str(nd.text)):
		nd.button_pressed = true
		return true
	for c in nd.get_children():
		q.append(c)
return false

